class Solution:
    def makesquare(self, matchsticks):
        total = sum(matchsticks)
        if total % 4 != 0:
            return False
        side = total // 4
        n = len(matchsticks)
        # bitmask DP: dp[mask] = sum of sticks in that subset
        # find all subsets summing to side, then cover all bits with 4 non-overlapping
        good = [mask for mask in range(1, 1 << n)
                if sum(matchsticks[i] for i in range(n) if mask >> i & 1) == side]
        full = (1 << n) - 1
        def dfs(remaining, sides_left):
            if sides_left == 1:
                return True
            for mask in good:
                if mask & remaining == mask:
                    if dfs(remaining ^ mask, sides_left - 1):
                        return True
            return False
        return dfs(full, 4)

