class Solution:
    def makesquare(self, matchsticks):
        total = sum(matchsticks)
        if total % 4 != 0:
            return False
        side = total // 4
        matchsticks.sort(reverse=True)
        if matchsticks[0] > side:
            return False
        buckets = [0] * 4
        def bt(idx):
            if idx == len(matchsticks):
                return buckets[0] == side and buckets[1] == side and buckets[2] == side
            seen = set()
            for i in range(4):
                if buckets[i] in seen:
                    continue
                if buckets[i] + matchsticks[idx] <= side:
                    seen.add(buckets[i])
                    buckets[i] += matchsticks[idx]
                    if bt(idx + 1):
                        return True
                    buckets[i] -= matchsticks[idx]
            return False
        return bt(0)

